import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import {
    Box,
    Paper,
    Typography,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    TextField,
    Select,
    MenuItem,
    FormControl,
    Checkbox,
    Alert,
    CircularProgress,
    IconButton,
    Tooltip,
    Accordion,
    AccordionSummary,
    AccordionDetails
} from '@mui/material';
import {
    Add as AddIcon,
    Save as SaveIcon,
    DragIndicator as DragIcon,
    ExpandMore as ExpandMoreIcon,
    Settings as SettingsIcon
} from '@mui/icons-material';
import TrashIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Trash.js";
import FAWButton from '../../../../../component-widget/FAWButton';
import FAWConfirmationDialog from '../../../../../component-widget/FAWConfirmationDialog';
import FAWTypography from '../../../../../component-widget/FAWTypography';

// Valid Key Personnel field names - matching KeyPersonnelModel properties exactly
// Based on KeyPersonnelModel.cs and QuestionnaireItem.CreateDataGrid<T>() default columns
const VALID_KP_FIELDS = [
    'Name',           // KeyPersonnelModel property - always required
    'Email',          // KeyPersonnelModel property - always required  
    'Position',       // KeyPersonnelModel property
    'Address',        // KeyPersonnelModel property
    'Nationality',    // KeyPersonnelModel property
    'OwnershipPercent', // KeyPersonnelModel property (decimal)
    'EmbargoedResident', // KeyPersonnelModel property (bool)
    'Roles',          // KeyPersonnelModel property (List<string>)
    'TaxID',          // KeyPersonnelModel property
    'Country'         // KeyPersonnelModel property
];

// Fields that can be deleted (not core required fields)
// Fields that CAN be removed (deletable)
// Country - Can be removed, heading locked, type locked to DropDownList
// Position, Address, Nationality, TaxID - Can be removed, heading can be changed, type locked to Textbox
const DELETABLE_FIELDS = ['Position', 'Address', 'Nationality', 'TaxID', 'Country'];

// Centralized configuration for locked fields - based on KeyPersonnelModel and QuestionnaireItem.GetColumnTypeFromProperty()
// 
// Fields that CANNOT be removed:
// - Name: heading locked, type locked to Textbox
// - Email: heading locked, type locked to Email
// - OwnershipPercent: heading locked, type locked to NumericTextbox
// - EmbargoedResident: heading locked, type locked to CheckBox
// - Roles: heading locked, type can be Textbox or DropDownList only
//
// Fields that CAN be removed:
// - Country: heading locked, type locked to DropDownList
// - Position, Address, Nationality, TaxID: heading can be changed, type locked to Textbox
//
const LOCKED_FIELD_CONFIG = {
    'Name': { 
        type: 'Textbox', 
        message: 'Type locked: must be Text Box', 
        typeLocked: true, 
        headingLocked: true,
        defaultHeading: 'Name',
        required: true
    },
    'Email': { 
        type: 'Email', 
        message: 'Type locked: must be Email Text Box', 
        typeLocked: true, 
        headingLocked: true,
        defaultHeading: 'Email',
        required: true
    },
    'OwnershipPercent': { 
        type: 'NumericTextbox', 
        message: 'Type locked: must be Numeric Text Box', 
        typeLocked: true, 
        headingLocked: true,
        defaultHeading: 'Ownership Percentage'
    },
    'EmbargoedResident': { 
        type: 'CheckBox', 
        message: 'Type locked: must be Check Box', 
        typeLocked: true, 
        headingLocked: true,
        defaultHeading: 'Embargoed Resident'
    },
    'Roles': { 
        type: 'Textbox', // Default type, can be changed to DropDownList
        message: 'Type can be Textbox or DropDownList only', 
        typeLocked: false, // Type CAN be changed (but only to allowed types via getFieldTypesForColumn)
        headingLocked: true,
        defaultHeading: 'Roles'
    },
    'Country': { 
        type: 'DropDownList', 
        message: 'Type locked: must be Drop Down List', 
        typeLocked: true, 
        headingLocked: true,
        refDomain: 'Country',
        defaultHeading: 'Country'
    },
    'Position': { 
        type: 'Textbox', 
        message: 'Type locked: must be Text Box', 
        typeLocked: true, 
        headingLocked: false, // Heading CAN be changed
        defaultHeading: 'Position'
    },
    'Address': { 
        type: 'Textbox', 
        message: 'Type locked: must be Text Box', 
        typeLocked: true, 
        headingLocked: false, // Heading CAN be changed
        defaultHeading: 'Address'
    },
    'Nationality': { 
        type: 'Textbox', 
        message: 'Type locked: must be Text Box', 
        typeLocked: true, 
        headingLocked: false, // Heading CAN be changed
        defaultHeading: 'Nationality'
    },
    'TaxID': { 
        type: 'Textbox', 
        message: 'Type locked: must be Text Box', 
        typeLocked: true, 
        headingLocked: false, // Heading CAN be changed
        defaultHeading: 'Tax ID'
    }
};

// Field types available for selection
const FIELD_TYPES = [
    'Textbox',
    'Email',
    'NumericTextbox',
    'CheckBox',
    'DropDownList'
];

// Get allowed field types based on column name
const getFieldTypesForColumn = (columnName) => {
    switch (columnName) {
        case 'Roles':
            // Roles can only be Textbox or DropDownList
            return ['Textbox', 'DropDownList'];
        default:
            return FIELD_TYPES;
    }
};

// Reference domains will be loaded dynamically from server

function KeyPersonnelFieldsConfiguration({ questionnaireItemId = 0, data, item, onConfigurationChange, isDeployed = false }) {
    // Add error boundary for theme issues
    const [hasError, setHasError] = useState(false);
    
    if (hasError) {
        return (
            <Box sx={{ p: 2, border: '1px solid', borderColor: 'divider', borderRadius: 1 }}>
                <Typography variant="h6" color="error" sx={{ mb: 1 }}>
                    Fields Configuration
                </Typography>
                <Typography variant="body2" sx={{ color: '#666666', fontSize: '14px' }}>
                    Component error occurred. Please refresh the page.
                </Typography>
            </Box>
        );
    }
    const [columns, setColumns] = useState([]);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState(null);
    const [success, setSuccess] = useState(null);
    const [expanded, setExpanded] = useState(true); // Start expanded by default
    const [refDomains, setRefDomains] = useState([]); // Dynamic reference domains
    const [loadingRefDomains, setLoadingRefDomains] = useState(false);
    
    // Delete confirmation dialog state
    const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
    const [columnToDelete, setColumnToDelete] = useState(null);

    // Try to resolve the actual questionnaireItemId from multiple sources
    const resolveQuestionnaireItemId = useCallback(() => {
        // Method 1: Use passed questionnaireItemId if > 0
        if (questionnaireItemId > 0) {
            console.log('Using passed questionnaireItemId:', questionnaireItemId);
            return questionnaireItemId;
        }

        // Method 2: Try to extract from data/item props
        const possibleIds = [
            item?.id, item?.Id,
            data?.id, data?.Id,
            data?.questionnaireItemId, data?.QuestionnaireItemId,
            data?.itemId, data?.ItemId
        ];
        
        for (const id of possibleIds) {
            if (id && id > 0) {
                console.log('Found questionnaireItemId from props:', id);
                return id;
            }
        }

        // Method 3: Try to get from hidden fields (for form context)
        try {
            const hiddenFields = document.querySelectorAll('input[id*="hdnQuestionnaireItemId"], input[name*="QuestionnaireItemId"]');
            for (const field of hiddenFields) {
                const hiddenId = parseInt(field.value) || 0;
                if (hiddenId > 0) {
                    console.log('Found questionnaireItemId from hidden field:', hiddenId);
                    return hiddenId;
                }
            }
        } catch (e) {
            console.log('Could not access hidden fields:', e.message);
        }

        // Method 4: Try to get from URL parameters
        try {
            const urlParams = new URLSearchParams(window.location.search);
            const urlId = parseInt(urlParams.get('questionnaireItemId') || urlParams.get('itemId')) || 0;
            if (urlId > 0) {
                console.log('Found questionnaireItemId from URL:', urlId);
                return urlId;
            }
        } catch (e) {
            console.log('Could not get ID from URL:', e.message);
        }

        console.log('No questionnaireItemId found, using 0 (new question)');
        return 0;
    }, [questionnaireItemId, data, item]);

    // Get the resolved ID
    const resolvedQuestionnaireItemId = resolveQuestionnaireItemId();
    
    // Debug: Check if we're accidentally in a form context
    useEffect(() => {
        const keyPersonnelDiv = document.getElementById('keyPersonnel');
        if (keyPersonnelDiv) {
            console.log('Found keyPersonnel div - this might be form context, not editor context');
            console.log('keyPersonnel div dataset:', keyPersonnelDiv.dataset);
        } else {
            console.log('No keyPersonnel div found - this is likely editor context');
        }
    }, []);

    // Helper functions
    const isFieldTypeLocked = (fieldName) => {
        return LOCKED_FIELD_CONFIG[fieldName] && LOCKED_FIELD_CONFIG[fieldName].typeLocked === true;
    };

    const getLockedType = (fieldName) => {
        return LOCKED_FIELD_CONFIG[fieldName]?.type || 'Textbox';
    };

    const isFieldHeadingLocked = (fieldName) => {
        return LOCKED_FIELD_CONFIG[fieldName] && LOCKED_FIELD_CONFIG[fieldName].headingLocked === true;
    };

    // Helper function to get default heading - matches QuestionnaireItem.ConvertPropertyNameToHeading exactly
    const getDefaultHeading = (fieldName) => {
        // Match backend ConvertPropertyNameToHeading switch statement exactly
        switch (fieldName) {
            case 'OwnershipPercent': return 'Ownership Percentage';
            case 'EmbargoedResident': return 'Embargoed Resident';
            case 'TaxID': return 'Tax ID';
            default: 
                // Convert camelCase to spaces - matches backend regex logic
                return fieldName.replace(/(?<!^)([A-Z][a-z]|(?<=[a-z])[A-Z])/g, ' $1').replace(/^./, (str) => str.toUpperCase()).trim();
        }
    };

    const isFieldRequired = (fieldName) => {
        return LOCKED_FIELD_CONFIG[fieldName]?.required === true;
    };

    const getAvailableFieldNames = () => {
        const usedFields = columns.map(col => col.name);
        return VALID_KP_FIELDS.filter(field => !usedFields.includes(field));
    };


    // Load reference domains dynamically from server
    const loadRefDomains = useCallback(async () => {
        if (refDomains.length > 0) return; // Already loaded
        
        setLoadingRefDomains(true);
        try {
            console.log('Loading reference domains from server...');
            
            const response = await axios.post('/FormsManagement/KeyPersonnelService.asmx/GetRefDomains',
                JSON.stringify({}),
                { headers: { 'Content-Type': 'application/json; charset=utf-8' } }
            );
            
            console.log('GetRefDomains response:', response);

            let domains = [];
            if (response.data) {
                // Handle different response formats from ASP.NET Web Service
                if (typeof response.data === 'string') {
                    domains = JSON.parse(response.data);
                } else if (response.data.d) {
                    // ASP.NET Web Services wrap JSON in a 'd' property
                    domains = JSON.parse(response.data.d);
                } else if (Array.isArray(response.data)) {
                    domains = response.data;
                } else {
                    domains = response.data;
                }
            }

            // Validate and set domains
            if (Array.isArray(domains) && domains.length > 0) {
                console.log(`Successfully loaded ${domains.length} reference domains:`, domains);
                setRefDomains(domains);
            } else {
                console.warn('No reference domains returned from server');
                setRefDomains([]);
            }
        } catch (err) {
            console.error('Error loading reference domains:', err);
            
            // Provide user-friendly error message
            if (err.response?.status === 500) {
                setError('Server error loading reference domains. Using fallback options.');
            } else if (err.response?.status === 404) {
                setError('Reference domain service not found. Using fallback options.');
            } else {
                setError(`Failed to load reference domains: ${err.message}.`);
            }
            
            // Set empty array on error
            setRefDomains([]);
        } finally {
            setLoadingRefDomains(false);
        }
    }, [refDomains.length]);


    // Load fallback columns when no data is available - matching QuestionnaireItem.CreateDataGrid<T>() defaults
    const loadFallbackColumns = () => {
        console.log('Loading fallback columns based on QuestionnaireItem.CreateDataGrid<T>() default structure');
        
        // These are the 8 default columns created by QuestionnaireItem.CreateDataGrid<T>() for KeyPersonnel
        const defaultColumns = [
            'Name', 'Email', 'Position', 'Address', 'Nationality', 'OwnershipPercent', 'EmbargoedResident', 'Roles'
        ];
        
        const loadedColumns = defaultColumns.map((fieldName, index) => {
            const config = LOCKED_FIELD_CONFIG[fieldName] || {};
            return {
                id: index + 1, // Ensure unique sequential IDs
                name: fieldName,
                heading: getDefaultHeading(fieldName), // Use backend heading logic consistently
                type: config.type || 'Textbox',
                required: config.required !== undefined ? config.required : true, // Default to true, matching backend CreateDataGrid behavior
                sequence: index + 1,
                width: 'auto',
                refDomain: config.refDomain || '',
                isMasked: false,
                canRelabel: !config.headingLocked,
                isCustom: false
            };
        });
        
        setColumns(loadedColumns);
        onConfigurationChange?.(loadedColumns);
        console.log('Loaded', loadedColumns.length, 'fallback columns');
    };

    // Load columns from server
    const loadColumns = useCallback(async () => {
        const actualId = resolvedQuestionnaireItemId;
        if (actualId === 0) return;
        
        // Don't reload if we already have columns (to prevent overriding manually added columns)
        if (columns.length > 0) {
            console.log('Columns already loaded, skipping reload to preserve manual changes');
            return;
        }
        
        setLoading(true);
        setError(null);

        try {
            console.log('Loading columns with resolved questionnaireItemId:', actualId);
            console.log('Original questionnaireItemId prop:', questionnaireItemId);
            
            // If no questionnaire item ID, load fallback columns immediately
            if (actualId === 0) {
                console.log('No resolved questionnaire item ID, loading fallback columns');
                loadFallbackColumns();
                return;
            }

            let response;
            // Try to load existing columns first
            response = await axios.post('/FormsManagement/KeyPersonnelService.asmx/GetExistingColumns', 
                JSON.stringify({ questionnaireItemId: actualId }), 
                {
                    headers: { 'Content-Type': 'application/json; charset=utf-8' }
                }
            );
            
            console.log('GetExistingColumns raw response:', response);
            console.log('GetExistingColumns response.data:', response.data);
            
            let existingColumns;
            try {
                existingColumns = JSON.parse(response.data.d || response.data);
                console.log('Parsed existing columns:', existingColumns);
            } catch (parseError) {
                console.error('Error parsing existing columns response:', parseError);
                existingColumns = [];
            }
            
            if (existingColumns && existingColumns.length > 0) {
                console.log('Loading', existingColumns.length, 'existing columns');
                const loadedColumns = existingColumns.map((col, index) => {
                    const fieldName = col.name || col.Name;
                    return {
                        id: col.id || (index + 1),
                        name: fieldName,
                        heading: col.heading || col.Heading || getDefaultHeading(fieldName), // Use backend heading logic
                        type: col.type || col.Type || 'Textbox',
                        required: col.required !== false && col.Required !== false,
                        sequence: col.sequence || col.index || col.Index || (index + 1),
                        refDomain: col.refDomain || col.optionsRefDomain || col.OptionsRefDomain || '',
                        isMasked: col.isMasked || col.IsMasked || false,
                        canRelabel: !isFieldHeadingLocked(fieldName), // Set based on backend logic
                        isCustom: false,
                        width: col.width || col.Width || 'auto'
                    };
                });
                setColumns(loadedColumns);
                onConfigurationChange?.(loadedColumns);
                setLoading(false);
                return;
            }

            // Load model columns if no existing columns found
            response = await axios.post('/FormsManagement/KeyPersonnelService.asmx/GetModelColumns', 
                JSON.stringify({ questionnaireItemId }), 
                {
                    headers: { 'Content-Type': 'application/json; charset=utf-8' }
                }
            );

            console.log('GetModelColumns response:', response.data);
            const modelColumns = JSON.parse(response.data.d || response.data);

            if (modelColumns && modelColumns.length > 0) {
                console.log('Loading', modelColumns.length, 'model columns');
                const loadedColumns = modelColumns.map((col, index) => {
                    const fieldName = col.name || col.Name;
                    return {
                        id: col.id || col.Id || (index + 1),
                        name: fieldName,
                        heading: col.heading || col.Heading || getDefaultHeading(fieldName), // Use backend heading logic
                        type: col.type || col.Type || 'Textbox',
                        required: col.required !== false && col.Required !== false,
                        sequence: col.sequence || col.index || col.Index || (index + 1),
                        refDomain: col.refDomain || col.optionsRefDomain || col.OptionsRefDomain || '',
                        isMasked: col.isMasked || col.IsMasked || false,
                        canRelabel: !isFieldHeadingLocked(fieldName), // Set based on backend logic
                        isCustom: false,
                        width: col.width || col.Width || 'auto'
                    };
                });
                setColumns(loadedColumns);
                onConfigurationChange?.(loadedColumns);
            } else {
                // Load fallback columns
                loadFallbackColumns();
            }
        } catch (err) {
            console.error('Error loading columns:', err);
            setError('Failed to load column configuration. Please try again.');
        } finally {
            setLoading(false);
        }
    }, [questionnaireItemId, onConfigurationChange]);

    // Save columns to server
    const saveColumns = async () => {
        const actualQuestionnaireItemId = resolvedQuestionnaireItemId;
        console.log('saveColumns called with resolved questionnaireItemId:', actualQuestionnaireItemId);
        console.log('Original questionnaireItemId prop:', questionnaireItemId);
        console.log('Current columns to save:', columns);
        
        
        if (columns.length > 10) {
            setError('Maximum of 10 columns allowed. You currently have ' + columns.length + ' columns.');
            return;
        }

        // Always try to call the API, but handle questionnaireItemId = 0 case
        if (actualQuestionnaireItemId === 0 || !actualQuestionnaireItemId) {
            console.log('Resolved QuestionnaireItemId is 0 - this is likely a new question. Will still call API for testing.');
        }

        setSaving(true);
        setError(null);
        setSuccess(null);

        try {
            // Map React state to backend DataGridEntryColumn structure exactly
            const columnData = columns.map((col, index) => ({
                // DataGridEntryColumn properties (match C# class exactly)
                Id: col.id || 0, // int Id
                QuestionnaireItemId: actualQuestionnaireItemId || 0, // int QuestionnaireItemId
                Name: col.name ? col.name.trim() : '', // string Name
                Heading: col.heading ? col.heading.trim() : '', // string Heading
                Type: col.type || 'Textbox', // string Type
                Index: index + 1, // int Index (corresponds to sequence)
                Required: col.required || false, // bool Required
                Width: col.width || 'auto', // string Width
                OptionsRefDomain: col.refDomain || '', // string OptionsRefDomain
                IsMasked: col.isMasked || false, // bool IsMasked
                
                // Additional properties for compatibility
                id: col.id || 0,
                name: col.name ? col.name.trim() : '',
                heading: col.heading ? col.heading.trim() : '',
                width: col.width || 'auto',
                type: col.type || 'Textbox',
                required: col.required || false,
                index: index + 1,
                sequence: col.sequence || (index + 1),
                isCustom: col.isCustom || false,
                optionsRefDomain: col.refDomain || '',
                refDomain: col.refDomain || '',
                isMasked: col.isMasked || false,
                canRelabel: col.canRelabel !== false,
                questionnaireItemId: actualQuestionnaireItemId || 0
            }));

            console.log('Sending save request with data:', {
                questionnaireItemId: actualQuestionnaireItemId,
                columnConfigJson: JSON.stringify(columnData)
            });

            const response = await axios.post('/FormsManagement/KeyPersonnelService.asmx/SaveColumnConfiguration', 
                JSON.stringify({
                    questionnaireItemId: actualQuestionnaireItemId,
                    columnConfigJson: JSON.stringify(columnData)
                }), 
                {
                    headers: { 'Content-Type': 'application/json; charset=utf-8' }
                }
            );

            console.log('Save response received:', response);
            console.log('Response data:', response.data);

            const result = JSON.parse(response.data.d || response.data);
            console.log('Parsed result:', result);
            
            if (result.success) {
                // Use only result.message to avoid redundant text like "saved successfully! Successfully saved..."
                setSuccess(result.message || 'Column configuration saved successfully!');
                onConfigurationChange?.(columns);
            } else {
                setError(result.message || 'Error saving column configuration');
            }
        } catch (err) {
            console.error('Error saving columns:', err);
            console.error('Error details:', {
                message: err.message,
                response: err.response?.data,
                status: err.response?.status,
                statusText: err.response?.statusText
            });
            
            let errorMessage = 'Error saving column configuration. ';
            if (err.response?.data) {
                errorMessage += `Server response: ${err.response.data}`;
            } else if (err.message) {
                errorMessage += `Error: ${err.message}`;
            } else {
                errorMessage += 'Please try again.';
            }
            
            setError(errorMessage);
        } finally {
            setSaving(false);
        }
    };

    // Add new custom column
    const addCustomColumn = () => {
        console.log('addCustomColumn called');
        console.log('Current columns before adding:', columns.map(c => ({ id: c.id, name: c.name })));
        
        const availableFields = getAvailableFieldNames();
        console.log('Available fields:', availableFields);
        
        if (availableFields.length === 0) {
            setError('No more fields available to add.');
            return;
        }

        if (columns.length >= 10) {
            setError('Maximum of 10 columns allowed.');
            return;
        }

        const fieldName = availableFields[0];
        const config = LOCKED_FIELD_CONFIG[fieldName] || {};
        
        // Generate unique temporary ID for new columns to avoid conflicts
        const maxId = Math.max(...columns.map(c => c.id), 0);
        const newColumn = {
            id: maxId + 1, // Unique temporary ID, will get proper ID when saved to match DataGridEntryColumn
            name: fieldName,
            heading: getDefaultHeading(fieldName), // Use backend heading logic
            type: config.type || 'Textbox', // Use locked type if available
            required: config.required !== undefined ? config.required : true, // Default to true, matching backend CreateDataGrid behavior
            sequence: columns.length + 1,
            width: 'auto',
            refDomain: config.refDomain || '', // Use refDomain from config if available
            isMasked: false,
            canRelabel: !config.headingLocked, // Set based on whether heading is locked
            isCustom: true
        };

        console.log('New column to add:', newColumn);
        
        const newColumns = [...columns, newColumn];
        console.log('Columns after adding:', newColumns.map(c => ({ id: c.id, name: c.name })));
        
        setColumns(newColumns);
        onConfigurationChange?.(newColumns);
        
        console.log('addCustomColumn completed');
    };

    // Open delete confirmation dialog
    const handleDeleteClick = (column) => {
        setColumnToDelete(column);
        setDeleteConfirmOpen(true);
    };

    // Confirm delete - actually remove the column
    const confirmDelete = () => {
        if (columnToDelete) {
            console.log('Deleting column:', columnToDelete.name);
            const newColumns = columns.filter(col => col.id !== columnToDelete.id);
            setColumns(newColumns);
            onConfigurationChange?.(newColumns);
        }
        setDeleteConfirmOpen(false);
        setColumnToDelete(null);
    };

    // Cancel delete
    const cancelDelete = () => {
        setDeleteConfirmOpen(false);
        setColumnToDelete(null);
    };

    // Update column - matches backend DataGridEntryColumn update logic
    const updateColumn = (id, field, value) => {
        console.log('updateColumn called with:', { id, field, value });
        console.log('Current columns:', columns.map(c => ({ id: c.id, name: c.name })));
        
        const newColumns = columns.map(col => {
            if (col.id === id) {
                const updatedCol = { ...col, [field]: value };
                
                // Auto-populate heading when column name changes - matches backend ConvertPropertyNameToHeading
                if (field === 'name' && value !== col.name) {
                    // Always update heading to match backend default logic
                    updatedCol.heading = getDefaultHeading(value);
                    
                    // If heading is locked for this field, use the locked heading
                    if (isFieldHeadingLocked(value)) {
                        updatedCol.heading = LOCKED_FIELD_CONFIG[value]?.defaultHeading || getDefaultHeading(value);
                    }
                    
                    // Auto-update type if it's locked for the new field - matches backend GetColumnTypeFromProperty
                    if (isFieldTypeLocked(value)) {
                        updatedCol.type = getLockedType(value);
                    } else if (isFieldTypeLocked(col.name) && !isFieldTypeLocked(value)) {
                        // If old type was locked but new is not, reset to default Textbox
                        updatedCol.type = 'Textbox';
                    }
                    
                    // Auto-update refDomain for fields that require it
                    if (LOCKED_FIELD_CONFIG[value]?.refDomain) {
                        updatedCol.refDomain = LOCKED_FIELD_CONFIG[value].refDomain;
                    } else if (LOCKED_FIELD_CONFIG[col.name]?.refDomain && !LOCKED_FIELD_CONFIG[value]?.refDomain) {
                        // If old refDomain was locked but new is not, clear it
                        updatedCol.refDomain = '';
                    }
                    
                    // Auto-update required status for locked fields
                    if (value === 'Name' || value === 'Email') {
                        updatedCol.required = true;
                    } else if (isFieldTypeLocked(value) && getLockedType(value) === 'CheckBox') {
                        // Checkboxes are typically not required by default unless explicitly set
                        updatedCol.required = false;
                    }
                }
                
                // Handle refDomain when type changes to/from DropDownList
                if (field === 'type') {
                    if (value === 'DropDownList' && !updatedCol.refDomain) {
                        // If changing to DropDownList and no refDomain set, use default if available
                        if (LOCKED_FIELD_CONFIG[updatedCol.name]?.refDomain) {
                            updatedCol.refDomain = LOCKED_FIELD_CONFIG[updatedCol.name].refDomain;
                        }
                    } else if (value !== 'DropDownList') {
                        // If changing away from DropDownList, clear refDomain unless it's locked
                        if (!LOCKED_FIELD_CONFIG[updatedCol.name]?.refDomain) {
                            updatedCol.refDomain = '';
                        }
                    }
                }
                
                return updatedCol;
            }
            return col;
        });
        setColumns(newColumns);
        onConfigurationChange?.(newColumns);
    };

    // Load columns when component mounts - always load fallback if no data
    useEffect(() => {
        const actualId = resolvedQuestionnaireItemId;
        console.log('KeyPersonnelFieldsConfiguration mounted with resolved questionnaireItemId:', actualId);
        console.log('Original questionnaireItemId prop:', questionnaireItemId);
        
        // Always load some data to show the interface
        if (actualId === 0) {
            console.log('No resolved questionnaire item ID, loading fallback columns immediately');
            loadFallbackColumns();
        } else {
            loadColumns();
        }

        // Load reference domains in the background
        loadRefDomains();
    }, []); // Only run on mount

    // Reload when questionnaireItemId changes
    useEffect(() => {
        const actualId = resolvedQuestionnaireItemId;
        if (actualId > 0) {
            console.log('Resolved QuestionnaireItemId changed to:', actualId, 'reloading columns');
            loadColumns();
        }
    }, [resolvedQuestionnaireItemId, loadColumns]);

    try {
        return (
            <>
            <Accordion 
                expanded={expanded} 
                onChange={(event, isExpanded) => setExpanded(isExpanded)}
                sx={{ mt: 2 }}
            >
            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                <Box display="flex" alignItems="center" gap={1}>
                    <SettingsIcon color="primary" />
                    <Typography variant="body1" sx={{ fontWeight: 600, fontSize: '14px' }}>
                        Fields Configuration
                    </Typography>
                </Box>
            </AccordionSummary>
            <AccordionDetails>
                <Box>
                    <FAWTypography variant="body2" sx={{ mb: 2, fontSize: '14px', color: '#282E37' }}>
                        Configure the Fields for your KeyPersonnel data grid. You can customize field labels and enable data masking. 
                        All default Field properties are loaded by default. <strong>Maximum 10 columns allowed.</strong>
                    </FAWTypography>
                    
                    {isDeployed && (
                        <Alert severity="warning" sx={{ mb: 2, '& .MuiAlert-message': { fontSize: '14px', color: '#282E37' } }}>
                            <strong>Read-Only Mode:</strong> This form version is currently active/deployed. Field configuration cannot be modified.
                        </Alert>
                    )}
                    

                    {error && (
                        <Alert severity="error" sx={{ mb: 2, '& .MuiAlert-message': { fontSize: '14px', color: '#282E37' } }} onClose={() => setError(null)}>
                            {error}
                        </Alert>
                    )}

                    {success && (
                        <Alert severity="success" sx={{ mb: 2, '& .MuiAlert-message': { fontSize: '14px', color: '#282E37' } }} onClose={() => setSuccess(null)}>
                            {success}
                        </Alert>
                    )}

                    {loading ? (
                        <Box display="flex" justifyContent="center" p={4}>
                            <CircularProgress />
                        </Box>
                    ) : (
                        <>
                            <TableContainer component={Paper} variant="outlined" sx={{ mb: 2 }}>
                                <Table size="medium" sx={{ 
                                    '& .MuiTableCell-root': { 
                                        verticalAlign: 'top',
                                        padding: '20px 16px'
                                    },
                                    '& .MuiTableBody-root .MuiTableRow-root': {
                                        '& .MuiTableCell-root': {
                                            paddingTop: '24px',
                                            paddingBottom: '24px'
                                        }
                                    }
                                }}>
                                    <TableHead>
                                        <TableRow>
                                            <TableCell>Order</TableCell>
                                            <TableCell>Column Name</TableCell>
                                            <TableCell>Display Heading</TableCell>
                                            <TableCell sx={{ width: 150, minWidth: 150 }}>Type</TableCell>
                                            <TableCell>Ref Domain</TableCell>
                                            <TableCell align="center">Required</TableCell>
                                            <TableCell align="center">Mask Data</TableCell>
                                            <TableCell>Actions</TableCell>
                                        </TableRow>
                                    </TableHead>
                                    <TableBody>
                                        {columns.map((column) => (
                                            <TableRow key={column.id}>
                                                <TableCell>
                                                    <Box display="flex" alignItems="center">
                                                        <DragIcon color="action" sx={{ mr: 1 }} />
                                                        {column.sequence}
                                                    </Box>
                                                </TableCell>
                                                <TableCell>
                                                    {column.isCustom ? (
                                                        <FormControl size="medium" fullWidth>
                                                            <Select
                                                                value={column.name}
                                                                onChange={(e) => updateColumn(column.id, 'name', e.target.value)}
                                                                disabled={isDeployed}
                                                            >
                                                                {[column.name, ...getAvailableFieldNames()].map(field => (
                                                                    <MenuItem key={field} value={field}>
                                                                        {field}
                                                                    </MenuItem>
                                                                ))}
                                                            </Select>
                                                        </FormControl>
                                                    ) : (
                                                        <Typography variant="body1" sx={{ fontWeight: 600, fontSize: '14px', color: '#282E37' }}>
                                                            {column.name}
                                                        </Typography>
                                                    )}
                                                </TableCell>
                                                <TableCell>
                                                    <TextField
                                                        size="medium"
                                                        fullWidth
                                                        value={column.heading}
                                                        onChange={(e) => updateColumn(column.id, 'heading', e.target.value)}
                                                        disabled={isFieldHeadingLocked(column.name) || isDeployed}
                                                        title={isFieldHeadingLocked(column.name) ? 
                                                            "This field label cannot be customized" : ""}
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    <div style={{ marginBottom: isFieldTypeLocked(column.name) ? '20px' : '0' }}>
                                                        <FormControl size="medium" fullWidth>
                                                            <Select
                                                                value={column.type}
                                                                onChange={(e) => updateColumn(column.id, 'type', e.target.value)}
                                                                disabled={isFieldTypeLocked(column.name) || isDeployed}
                                                            >
                                                                {getFieldTypesForColumn(column.name).map(type => (
                                                                    <MenuItem key={type} value={type}>
                                                                        {type}
                                                                    </MenuItem>
                                                                ))}
                                                            </Select>
                                                        </FormControl>
                                                    </div>
                                                    {isFieldTypeLocked(column.name) && (
                                                        <div style={{ 
                                                            marginTop: '16px',
                                                            paddingTop: '4px',
                                                            borderTop: '0px solid transparent'
                                                        }}>
                                                            <Typography 
                                                                variant="caption" 
                                                                component="div"
                                                                style={{ 
                                                                    color: '#666666', 
                                                                    fontSize: '11px', 
                                                                    lineHeight: '1.5',
                                                                    marginTop: '4px'
                                                                }}
                                                            >
                                                                {LOCKED_FIELD_CONFIG[column.name]?.message}
                                                            </Typography>
                                                        </div>
                                                    )}
                                                </TableCell>
                                                <TableCell>
                                                    {column.type === 'DropDownList' ? (
                                                        <FormControl size="medium" fullWidth>
                                                            <Select
                                                                value={column.refDomain || ''}
                                                                onChange={(e) => updateColumn(column.id, 'refDomain', e.target.value)}
                                                                displayEmpty
                                                                disabled={isFieldTypeLocked(column.name) && LOCKED_FIELD_CONFIG[column.name]?.refDomain || isDeployed}
                                                                onOpen={() => loadRefDomains()}
                                                            >
                                                                <MenuItem value="">
                                                                    <em>
                                                                        {loadingRefDomains 
                                                                            ? 'Loading...' 
                                                                            : refDomains.length === 0 
                                                                                ? 'No Ref Domains Available' 
                                                                                : 'Select Ref Domain'
                                                                        }
                                                                    </em>
                                                                </MenuItem>
                                                                {refDomains.map(domain => (
                                                                    <MenuItem 
                                                                        key={domain.value || domain} 
                                                                        value={domain.value || domain}
                                                                    >
                                                                        {domain.text || domain.name || domain}
                                                                    </MenuItem>
                                                                ))}
                                                            </Select>
                                                        </FormControl>
                                                    ) : (
                                                        <Typography variant="body1" sx={{ color: '#666666', fontSize: '14px' }}>
                                                            N/A
                                                        </Typography>
                                                    )}
                                                </TableCell>
                                                <TableCell align="center">
                                                    <Checkbox
                                                        checked={column.required}
                                                        onChange={(e) => updateColumn(column.id, 'required', e.target.checked)}
                                                        disabled={isDeployed}
                                                    />
                                                </TableCell>
                                                <TableCell align="center">
                                                    <Checkbox
                                                        checked={column.isMasked}
                                                        onChange={(e) => updateColumn(column.id, 'isMasked', e.target.checked)}
                                                        disabled={isDeployed}
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    {(column.isCustom || DELETABLE_FIELDS.includes(column.name)) ? (
                                                        <Tooltip title="Remove Column">
                                                            <span>
                                                                <IconButton 
                                                                    size="small" 
                                                                    aria-label="delete"
                                                                    onClick={() => handleDeleteClick(column)}
                                                                    disabled={isDeployed}
                                                                    color="error"
                                                                    sx={{
                                                                        border: '1px solid',
                                                                        borderColor: 'error.main',
                                                                        borderRadius: '8px',
                                                                        backgroundColor: 'transparent',
                                                                        width: '32px',
                                                                        height: '32px',
                                                                        minWidth: '32px',
                                                                        minHeight: '32px',
                                                                        padding: '4px',
                                                                        '&:hover': {
                                                                            backgroundColor: 'error.light',
                                                                        },
                                                                        '&.Mui-disabled': {
                                                                            borderColor: 'action.disabled',
                                                                            color: 'action.disabled'
                                                                        }
                                                                    }}
                                                                >
                                                                    <TrashIcon size="md" />
                                                                </IconButton>
                                                            </span>
                                                        </Tooltip>
                                                    ) : (
                                                        <Box sx={{ width: '32px', height: '32px' }} />
                                                    )}
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            </TableContainer>

                            <Box display="flex" gap={2} justifyContent="flex-end">
                                <FAWButton
                                    variant="outlined"
                                    startIcon={<AddIcon />}
                                    onClick={addCustomColumn}
                                    disabled={columns.length >= 10 || getAvailableFieldNames().length === 0 || isDeployed}
                                >
                                    Add Custom Column
                                </FAWButton>
                                <FAWButton
                                    variant="contained"
                                    startIcon={saving ? <CircularProgress size={16} /> : <SaveIcon />}
                                    onClick={saveColumns}
                                    disabled={saving || isDeployed}
                                    title={isDeployed ? 'Cannot save - form version is deployed' : ''}
                                >
                                    {saving ? 'Saving...' : 
                                     isDeployed ? 'Read-Only Mode' : 
                                     'Save Fields Configuration'}
                                </FAWButton>
                            </Box>
                        </>
                    )}
                </Box>
            </AccordionDetails>
            </Accordion>
            
            {/* Delete Confirmation Dialog */}
            <FAWConfirmationDialog
                open={deleteConfirmOpen}
                title="Confirm Delete"
                message={`Are you sure you want to remove the "${columnToDelete?.name}" column? This action cannot be undone.`}
                onConfirm={confirmDelete}
                onCancel={cancelDelete}
                confirmText="Yes, Delete"
                cancelText="Cancel"
                severity="error"
            />
            </>
        );
    } catch (error) {
        console.error('KeyPersonnelFieldsConfiguration render error:', error);
        setHasError(true);
        return null;
    }
}

export default KeyPersonnelFieldsConfiguration;
