import React, { useEffect, useState, useCallback, useMemo } from "react";
import Box from "@mui/material/Box";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWInput from "../../../../component-widget/FAWInput";
import KeyPersonnelFieldsConfiguration from "./shared/KeyPersonnelFieldsConfiguration";

export default function QueKeyPersonnelEditor({ data, questionId, onSave, onClose, saveRef, isDefaultLanguage = true, isDeployed = false }) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      isHidden: false,
      notes: false,
      isOwnershipThreshold: false,
      ownershipPercent: "",
      isBypassThreshold: false,
      bypassThresholdPercent: ""
    }
  );
  
  // Use questionId prop directly (from editingQuestionId in ControlSearch) - most reliable source
  // Fall back to data.id only if questionId is not provided
  const questionnaireItemId = useMemo(() => {
    // questionId comes directly from ControlSearch.editingQuestionId - most reliable
    if (questionId && questionId > 0) {
      console.log('QueKeyPersonnelEditor - Using questionId prop:', questionId);
      return questionId;
    }
    // Fallback to data.id if questionId not available
    const id = item?.id || item?.Id || 
               data?.id || data?.Id || 
               data?.questionnaireItemId || data?.QuestionnaireItemId ||
               data?.itemId || data?.ItemId || 0;
    
    console.log('QueKeyPersonnelEditor - Fallback questionnaireItemId:', id);
    return id;
  }, [questionId, item?.id, item?.Id, data?.id, data?.Id, data?.questionnaireItemId, data?.QuestionnaireItemId, data?.itemId, data?.ItemId]);

  const [errors, setErrors] = useState({});

  useEffect(() => { 
    if (data) {
      console.log('QueKeyPersonnelEditor received data:', data);
      console.log('QueKeyPersonnelEditor questionId prop:', questionId);
      setItem(prev => ({ ...prev, ...data })); 
    }
  }, [data, questionId]);
  
  // Validation function matching legacy RegularExpressionValidator pattern: ^([1-9]|[1-9][0-9]|100)$
  // Legacy error message: "Please enter a value between 1 and 100."
  const validatePercent = (value) => {
    if (!value || value.trim() === "") {
      return "Please enter a value between 1 and 100.";
    }
    const num = Number(value);
    if (Number.isNaN(num)) {
      return "Please enter a value between 1 and 100.";
    }
    if (num < 1 || num > 100) {
      return "Please enter a value between 1 and 100.";
    }
    // Check regex pattern: 1-9, 10-99, or 100 (matching legacy ValidationExpression)
    const regex = /^([1-9]|[1-9][0-9]|100)$/;
    if (!regex.test(String(Math.trunc(num)))) {
      return "Please enter a value between 1 and 100.";
    }
    return null;
  };

  const validateForm = () => {
    const newErrors = {};
    
    // Validate Ownership Threshold if enabled (matching legacy RequiredFieldValidator)
    if (item.isOwnershipThreshold) {
      const ownershipError = validatePercent(item.ownershipPercent);
      if (ownershipError) {
        newErrors.ownershipPercent = ownershipError;
      }
    }
    
    // Validate Bypass Threshold if enabled (matching legacy RequiredFieldValidator)
    if (item.isBypassThreshold) {
      const bypassError = validatePercent(item.bypassThresholdPercent);
      if (bypassError) {
        newErrors.bypassThresholdPercent = bypassError;
      }
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = () => {
    // Validate before saving
    if (!validateForm()) {
      return; // Don't save if validation fails
    }
    onSave?.(item);
  };

  const handleOwnershipThresholdChange = (e) => {
    const checked = e.target.checked;
    setItem(prev => {
      const newItem = { ...prev, isOwnershipThreshold: checked };
      // Matching legacy behavior: when checked, keep existing value; when unchecked, set to "100"
      if (!checked) {
        // Clear ownership percent when unchecked and set default to "100" (matching legacy behavior)
        newItem.ownershipPercent = "100";
        // Clear error when unchecked
        setErrors(prev => {
          const newErrors = { ...prev };
          delete newErrors.ownershipPercent;
          return newErrors;
        });
      } else {
        // When checked, keep existing value (or empty if new) - matching legacy: ownershipPercent.Text = isOwnershipThreshold.Checked ? ownershipPercent.Text : "100"
        // Don't set a default - let RequiredFieldValidator handle empty validation
        // Clear error when enabling
        setErrors(prev => {
          const newErrors = { ...prev };
          delete newErrors.ownershipPercent;
          return newErrors;
        });
      }
      return newItem;
    });
  };

  const handleOwnershipPercentChange = (e) => {
    const value = e.target.value;
    // Allow typing any value - don't clamp
    setItem(prev => ({ ...prev, ownershipPercent: value }));
    
    // Clear error when user starts typing
    if (errors.ownershipPercent) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors.ownershipPercent;
        return newErrors;
      });
    }
    
    // Validate when value changes (but allow typing beyond 100)
    if (value !== "") {
      const error = validatePercent(value);
      if (error) {
        setErrors(prev => ({ ...prev, ownershipPercent: error }));
      }
    }
  };

  const handleBypassThresholdChange = (e) => {
    const checked = e.target.checked;
    setItem(prev => {
      const newItem = { ...prev, isBypassThreshold: checked };
      // Matching legacy behavior: when checked, keep existing value; when unchecked, set to "100"
      if (!checked) {
        // Clear bypass threshold percent when unchecked and set default to "100" (matching legacy behavior)
        newItem.bypassThresholdPercent = "100";
        // Clear error when unchecked
        setErrors(prev => {
          const newErrors = { ...prev };
          delete newErrors.bypassThresholdPercent;
          return newErrors;
        });
      } else {
        // When checked, keep existing value (or empty if new) - matching legacy: bypassThresholdPercent.Text = isBypassThreshold.Checked ? bypassThresholdPercent.Text : "100"
        // Don't set a default - let RequiredFieldValidator handle empty validation
        // Clear error when enabling
        setErrors(prev => {
          const newErrors = { ...prev };
          delete newErrors.bypassThresholdPercent;
          return newErrors;
        });
      }
      return newItem;
    });
  };

  const handleBypassThresholdPercentChange = (e) => {
    const value = e.target.value;
    // Allow typing any value - don't clamp
    setItem(prev => ({ ...prev, bypassThresholdPercent: value }));
    
    // Clear error when user starts typing
    if (errors.bypassThresholdPercent) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors.bypassThresholdPercent;
        return newErrors;
      });
    }
    
    // Validate when value changes (but allow typing beyond 100)
    if (value !== "") {
      const error = validatePercent(value);
      if (error) {
        setErrors(prev => ({ ...prev, bypassThresholdPercent: error }));
      }
    }
  };
  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} questionType="KeyPersonnel" isDeployed={isDeployed} />
      <Box sx={{ display: "flex", flexDirection: "column", gap: 2, mt: 2 }}>
        <FAWCheckbox 
          label="Bold in PDF"
          checked={!!item.notes} 
          onChange={(e)=> setItem(prev=>({ ...prev, notes: e.target.checked }))}
        />
        <FAWCheckbox 
          label="Hide in PDF"
          checked={!!item.isHidden} 
          onChange={(e)=> setItem(prev=>({ ...prev, isHidden: e.target.checked }))}
        />
        <FAWCheckbox
          label="Enable Ownership Threshold"
          checked={!!item.isOwnershipThreshold}
          onChange={handleOwnershipThresholdChange}
          labelStyle={{ fontSize: '12px' }}
        />
        {item.isOwnershipThreshold && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, my: 1, mb: 2 }}>
            <FAWInput
              label="Ownership Threshold"
              type="number"
              value={item.ownershipPercent || ""}
              onChange={handleOwnershipPercentChange}
              inputProps={{ maxLength: 3 }}
              error={!!errors.ownershipPercent}
              helperText={errors.ownershipPercent || "When checked, the ownership percentage must be equal to or greater than the number entered here to submit the form."}
              required
              fullWidth={false}
              sx={{ width: '50%' }}
            />
          </Box>
        )}
        <FAWCheckbox
          label="Enable Threshold Bypass"
          checked={!!item.isBypassThreshold}
          onChange={handleBypassThresholdChange}
          labelStyle={{ fontSize: '12px' }}
        />
        {item.isBypassThreshold && (
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, my: 1, mb: 2 }}>
            <FAWInput
              label="Bypass Threshold"
              type="number"
              value={item.bypassThresholdPercent || ""}
              onChange={handleBypassThresholdPercentChange}
              inputProps={{ maxLength: 3 }}
              error={!!errors.bypassThresholdPercent}
              helperText={errors.bypassThresholdPercent || "When checked, allows you to bypass the ownership threshold and set an arbitrary number that states you have no owners who own more than X% of the company."}
              required
              fullWidth={false}
              sx={{ width: '50%' }}
            />
          </Box>
        )}
        
        {/* Key Personnel Fields Configuration */}
        <KeyPersonnelFieldsConfiguration 
          questionnaireItemId={questionnaireItemId}
          data={data}
          item={item}
          onConfigurationChange={(config) => {
            console.log('Fields configuration changed:', config);
            setItem(prev => ({ ...prev, fieldsConfiguration: config }));
          }}
          isDeployed={isDeployed}
        />
      </Box>
    </EditorShell>
  );
}



